<script setup lang="ts">
import { onMounted, ref } from "vue"; import { Activity, RefreshCw, ShieldCheck } from "lucide-vue-next"; import { api } from "@/lib/api";
const panels = ["status", "game", "recipes", "rag", "llm", "config"]; const data = ref<Record<string, Record<string, unknown>>>({}); const output = ref("就绪。");
async function load() { await Promise.all(panels.map(async (name) => { try { data.value[name] = await api.admin(name); } catch (cause) { data.value[name] = { 状态: cause instanceof Error ? cause.message : "加载失败" }; } })); }
async function action(name: string) { if (name === "rebuild-wiki" && !confirm("确认重建 Wiki 索引？")) return; output.value = "执行中…"; try { output.value = JSON.stringify(await api.adminAction(name), null, 2); await load(); } catch (cause) { output.value = cause instanceof Error ? cause.message : "操作失败"; } }
onMounted(load);
</script>
<template><section class="admin-page"><header class="admin-hero"><div><p class="eyebrow">LOOPBACK CONSOLE</p><h1>开发者控制台</h1><p>系统、游戏、数据与 Agent 的本地诊断面板。</p></div><ShieldCheck :size="38" /></header><div class="admin-grid"><article v-for="(value, key) in data" :key="key" class="admin-panel"><h2>{{ key }}</h2><dl><template v-for="(item, label) in value" :key="String(label)"><dt>{{ label }}</dt><dd>{{ String(item ?? "—") }}</dd></template></dl></article></div><section class="diagnostics"><div><Activity :size="18" /><h2>诊断操作</h2></div><div class="action-row"><button type="button" @click="action('health-check')">健康检查</button><button type="button" @click="action('reconnect-log')">重连日志</button><button type="button" class="danger" @click="action('rebuild-wiki')">重建 Wiki</button><button type="button" aria-label="刷新面板" @click="load"><RefreshCw :size="16" /></button></div><pre>{{ output }}</pre></section></section></template>
